    expect(chart).toHaveAttribute('width', '800');
    expect(chart).toHaveAttribute('height', '400');

    // Simulate window resizing to smaller size
    // This is where the bug occurs - contentRect might not reflect the actual size change
    // when min-width constraints are involved
    mockGetBoundingClientRect.mockReturnValueOnce({
      width: 300, // Now smaller due to min-width constraint
      height: 150,
      top: 0,
      right: 300,
      bottom: 150,
      left: 0,
    });

    act(() => {
      // The bug: ResizeObserver uses contentRect which might not change
      // when the element is constrained by min-width
      notifyResizeObserverChange([{
        contentRect: {
          width: 250, // contentRect shows smaller than actual visible area
          height: 125
        }
      }]);
    });

    // With the bug, the chart would stay at 800x400 instead of resizing to 300x150
    // The test should fail here, demonstrating the bug
    expect(chart).toHaveAttribute('width', '300');
    expect(chart).toHaveAttribute('height', '150');
  });

  it('should use getBoundingClientRect for both initial and resize events', () => {
    const mockGetBoundingClientRect = vi.fn();

    // Initial large size
    mockGetBoundingClientRect.mockReturnValueOnce({
      width: 800,
      height: 400,
      top: 0,
      right: 800,
      bottom: 400,
      left: 0,
    });

    const { container } = render(
      <ResponsiveContainer width="100%" height="100%" minWidth={300}>
        <div data-testid="chart" />
      </ResponsiveContainer>,
    );

    const containerElement = container.querySelector('.recharts-responsive-container');
    containerElement.getBoundingClientRect = mockGetBoundingClientRect;

    const chart = screen.getByTestId('chart');
    expect(chart).toHaveAttribute('width', '800');
    expect(chart).toHaveAttribute('height', '400');

    // Resize to smaller size
    mockGetBoundingClientRect.mockReturnValueOnce({
      width: 300,
      height: 150,
      top: 0,
      right: 300,
      bottom: 150,
      left: 0,
    });

    act(() => {
      // Even if contentRect shows different values, we should use getBoundingClientRect
      notifyResizeObserverChange([{
        contentRect: {
          width: 250, // Different from bounding rect due to constraints
          height: 125
        }
      }]);
    });

    // This should pass if the fix is applied
    expect(chart).toHaveAttribute('width', '300');
    expect(chart).toHaveAttribute('height', '150');
  });
});

